  'huzhou/bamboo': ('Anji Bambu Denizi', 'Uçsuz yeşil bambu ormanları sinemaya ilham verdi ve havayı serin tutar.'),
  'huzhou/silkworm': ('İpek Böceği', 'Tai Gölü\'nün güney kıyısı, bin yıldır dut ipekçiliğinin merkezidir.'),
  'huzhou/whitetea': ('Anji Beyaz Çayı', 'Soluk yeşil yaprakları ve tatlı tadıyla Anji beyaz çayı Çin\'in nadidelerindendir.'),
  'quzhou/go': ('Go Oyunu', 'Lanke Dağı efsanesiyle Go oyununun kutsandığı şehir \'Go diyarı\' sayılır.'),
  'quzhou/peaks': ('Jianglang Dağı', 'Gökyüzüne uzanan üç dev taş sütun, UNESCO mirası eşsiz bir manzaradır.'),
  'quzhou/ponkan': ('Quzhou Mandalinası', 'Tatlı kabuklu ponkan mandalinası, ılıman tepelerin kış armağanıdır.'),
  'quzhou/cake': ('Közde Pide', 'Fırın duvarında pişirilen çıtır susam pidesi, yerel kahvaltının klasiğidir.'),
  'huainan/tofu': ('Tofu\'nun Doğduğu Yer', 'Bagong Dağı\'nda 2.000 yıl önce icat edilen tofu, dünya mutfağına buradan yayıldı.'),
  'huainan/coalmine': ('Kömür Şehri', 'Zengin kömür yataklarıyla Huainan, Doğu Çin\'in enerji üssüdür.'),
  'huainan/oldtown': ('Shou Antik Kenti', 'Tam korunmuş Song dönemi şehir suru, antik savunma mimarisinin nadide örneğidir.'),
  'huainan/classic': ('Huainanzi', 'Prens Liu An\'ın derlediği klasik felsefe metni bu topraklarda yazıldı.'),
  'jingdezhen/porcelain': ('Porselen Başkenti', 'Bin yıldır imparatorluk porselenini üreten şehir, dünyanın \'porselen başkenti\'dir.'),
  'jingdezhen/kiln': ('Antik Fırın', 'Odunla yakılan ejderha biçimli fırınlar, geleneksel porselen pişirme sanatını yaşatır.'),
  'jingdezhen/bluewhite': ('Mavi-Beyaz Porselen', 'Kobalt mavisi desenli beyaz porselen, şehrin dünyaca tanınan imzasıdır.'),
  'jingdezhen/painting': ('Porselen Resmi', 'Usta ressamların ince fırçayla işlediği porselen, bir tablo kadar değerlidir.'),
  'jian/jinggang': ('Jinggang Dağları', 'Çin devriminin ilk üssü olan sisli dağlar, \'kızıl turizmin\' kalbidir.'),
  'jian/torch': ('Devrim Kıvılcımı', '\'Tek kıvılcım bozkırı tutuşturur\' sözünün doğduğu topraklar, tarihî bir anıt-alandır.'),
  'jian/academy': ('Bailuzhou Akademisi', 'Gan Nehri adasındaki bin yıllık akademi, sayısız imparatorluk âlimi yetiştirdi.'),
  'jian/pine': ('Jinggang Çamları', 'Sislerin arasından yükselen kızıl çamlar, dağ ruhunun ve dayanıklılığın simgesidir.'),
  'nanping/wuyi': ('Wuyi Dağları', 'Kızıl kayalıkları ve yeşil vadileriyle UNESCO mirası dağlar, doğa ve kültür hazinesidir.'),
  'nanping/rocktea': ('Da Hong Pao', 'Kayalıklarda yetişen \'Büyük Kızıl Cübbe\' oolong çayı, dünyanın en pahalı çaylarındandır.'),
  'nanping/bambooraft': ('Dokuz Kıvrım Salı', 'Bambu sallarla süzülen Dokuz Kıvrım Deresi, kızıl kayalar arasında akar.'),
  'nanping/scholar': ('Zhu Xi', 'Neo-Konfüçyüsçülüğün kurucusu Zhu Xi, dersini bu dağ eteklerinde verdi.'),
  'shenzhen/skyscraper': ('Gökdelenler', 'Bir balıkçı köyünden 40 yılda yükselen gökdelen ormanı, Çin reformunun mucizesidir.'),
  'shenzhen/chip': ('Teknoloji Şehri', 'Huaqiangbei elektronik çarşısı ve dev teknoloji şirketleriyle Shenzhen \'Çin\'in Silikon Vadisi\'dir.'),
  'shenzhen/miniature': ('Dünya Penceresi', 'Dünyanın ünlü yapılarının minyatürlerini bir araya getiren tema parkı şehrin simgesidir.'),
  'shenzhen/mangrove': ('Shenzhen Körfezi', 'Mangrov ormanlı körfez, göçmen kuşların ve ak balıkçılların uğrağıdır.'),
  'xian/terracotta': ('Toprak Ordu', 'İmparator Qin\'in mezarını koruyan binlerce pişmiş toprak asker, dünyanın sekizinci harikası sayılır.'),
  'xian/citywall': ('Şehir Suru', 'Çin\'in en eksiksiz korunmuş Ming şehir suru, üzerinde bisikletle turlanır.'),
  'xian/drumtower': ('Çan Kulesi', 'Şehrin tam merkezindeki Ming çan kulesi, eski başkentin kalbini simgeler.'),
  'xian/roujiamo': ('Roujiamo', 'Çıtır ekmeğe doldurulan baharatlı et \'roujiamo\', İpek Yolu\'nun ilk hamburgeridir.'),
  'suzhou/garden': ('Klasik Bahçeler', 'Kayalık, havuz ve köşkleriyle ince tasarlanmış bahçeler UNESCO mirasıdır.'),
  'suzhou/watertown': ('Su Kasabası', 'Kanalları, taş köprüleri ve beyaz evleriyle Suzhou \'Doğu\'nun Venedik\'i\'dir.'),
  'suzhou/embroidery': ('Su İşlemesi', 'İki yüzü farklı işlenen ipek nakış, bin yıllık bir Suzhou zanaatıdır.'),
  'suzhou/kunqu': ('Kunqu Operası', 'Tüm Çin operalarının anası sayılan zarif Kunqu, burada doğdu.'),
  'kunming/stoneforest': ('Taş Orman', 'Milyonlarca yılda oyulan dev kireçtaşı sütunları, ürpertici bir taş labirenti oluşturur.'),
  'kunming/springcity': ('Bahar Şehri', 'Yıl boyu ılıman iklimiyle Kunming, çiçeklerin hiç solmadığı \'bahar şehri\'dir.'),
  'kunming/seagull': ('Kırmızı Gagalı Martılar', 'Her kış Sibirya\'dan gelen binlerce martı, göl kıyısını beyaza boyar.'),
  'kunming/ricenoodle': ('Köprü Eriştesi', 'Sıcak et suyuna masada eklenen ince pirinç eriştesi, Yunnan\'ın imza yemeğidir.'),
  'jinan/spring': ('Pınarlar Şehri', 'Yerden fışkıran 72 ünlü pınar, Jinan\'a \'pınarlar şehri\' adını verir.'),
  'jinan/daminglake': ('Daming Gölü', 'Söğüt ve nilüferlerle çevrili şehir gölü, pınar sularıyla beslenir.'),
  'jinan/buddhamountain': ('Bin Buda Dağı', 'Yamaçlarına oyulmuş yüzlerce Buda figürüyle dağ, bir hac yeridir.'),
  'jinan/poet': ('Li Qingzhao', 'Çin\'in en büyük kadın şairi Li Qingzhao bu pınarlar şehrinde doğdu.'),
  'ningbo/library': ('Tianyi Kütüphanesi', '450 yıllık Tianyi Ge, Asya\'nın ayakta kalan en eski özel kütüphanesidir.'),
  'ningbo/port': ('Liman', 'Ningbo-Zhoushan, kargo hacmiyle dünyanın en yoğun limanıdır.'),
  'ningbo/tangyuan': ('Tangyuan', 'Susam dolgulu pirinç unu topları \'tangyuan\', şehrin tatlı imzasıdır.'),
  'ningbo/seafood': ('Deniz Ürünleri', 'Doğu Çin Denizi\'nin sarı kroker balığı ve yengeci yerel sofranın temelidir.'),
  'shijiazhuang/bridge': ('Zhaozhou Köprüsü', '1.400 yıllık taş kemer köprü, dünyanın en eski açık tympanonlu köprüsüdür.'),
  'shijiazhuang/clifftemple': ('Cangyan Dağı', 'Uçurumlar arasına asılı tapınak köprüsü, sayısız filme dekor oldu.'),
  'shijiazhuang/redbase': ('Xibaipo', 'Yeni Çin\'in kuruluşunun planlandığı köy, \'kırmızı turizmin\' kutsal durağıdır.'),
  'shijiazhuang/pharma': ('İlaç Şehri', 'Çin\'in en büyük ilaç üreticilerinden biri olan şehir, antibiyotik üssüdür.'),
  'taiyuan/jincitemple': ('Jinci Tapınağı', 'Üç bin yıllık heykelleri ve pınarlarıyla Jinci, kuzey Çin\'in en zarif tapınak bahçesidir.'),
  'taiyuan/coalcart': ('Kömür Diyarı', 'Shanxi\'nin kömür yatakları Çin\'in enerjisini besler; Taiyuan bu zenginliğin başkentidir.'),
  'taiyuan/vinegar': ('Shanxi Sirkesi', 'Yıllandırılmış olgun sirke, Shanxi mutfağının vazgeçilmez ekşisidir.'),
  'taiyuan/twinpagoda': ('İkiz Pagodalar', 'Şehrin simgesi olan iki sekizgen Ming pagodası, yan yana yükselir.'),
  'hohhot/lamatemple': ('Dazhao Tapınağı', 'Gümüş Buda heykeliyle ünlü Tibet Budist manastırı, şehrin manevi merkezidir.'),
  'hohhot/dairy': ('Süt Başkenti', 'Çin\'in en büyük süt markaları burada doğdu; şehir \'süt şehri\' diye anılır.'),
  'hohhot/wrestling': ('Moğol Güreşi', 'Naadam şenliğinin gözde yarışı boke güreşi, bozkır gücünün gösterisidir.'),
  'hohhot/prairie': ('Bozkır', 'Şehrin ötesinde uzanan yeşil Moğol bozkırları, at ve sürülerle doludur.'),
  'sanya/resortbeach': ('Tropik Plaj', 'Yalong Körfezi\'nin pudra gibi kumları ve turkuaz suları Çin\'in Hawaii\'sidir.'),
  'sanya/guanyin': ('Nanshan Guanyin', 'Denizin üstünde yükselen 108 metrelik Guanyin heykeli, dünyanın en yüksek tanrıça heykellerindendir.'),
  'sanya/diving': ('Dalış', 'Sıcak berrak suları ve mercan resifleriyle Sanya, Çin\'in dalış cennetidir.'),
  'sanya/coconutdrink': ('Hindistan Cevizi', 'Tropik bahçelerden toplanan taze hindistan cevizi suyu, adanın serinliğidir.'),
  'yangzhou/slenderlake': ('İnce Batı Gölü', 'Söğütleri ve beyaz köprüleriyle ince uzun göl, bir resim kadar zariftir.'),
  'yangzhou/friedrice': ('Yangzhou Pilavı', 'Karides ve yumurtayla harmanlanan altın pilav, dünyaca ünlü bir klasiktir.'),
  'yangzhou/morningtea': ('Sabah Çayı', 'Buğulama börek ve demli çayla yapılan zarif kahvaltı, Yangzhou\'nun ritüelidir.'),
  'yangzhou/gegarden': ('Ge Bahçesi', 'Dört mevsimi taşlarla canlandıran bambu bahçesi, klasik tasarımın başyapıtıdır.'),
  'weihai/navalisland': ('Liugong Adası', 'Beiyang Donanması\'nın üssü olan ada, modern Çin\'in deniz tarihine tanıklık eder.'),
  'weihai/swan': ('Kuğu Gölü', 'Her kış Sibirya\'dan gelen yüzlerce ötücü kuğu, kıyı lagününü süsler.'),
  'weihai/seacucumber': ('Deniz Hıyarı', 'Soğuk temiz sularda yetişen deniz hıyarı, şehrin en değerli deniz ürünüdür.'),
  'weihai/cape': ('Çin\'in Ucu', 'Çin\'in en doğu burnu, güneşin ülkeyi ilk selamladığı yerdir.'),
  'handan/taichi': ('Tai Chi', 'Yang ve Wu üsluplarının doğduğu Guangfu kasabası, taijiquan\'ın memleketidir.'),
  'handan/congtai': ('Congtai Terası', 'Antik Zhao Krallığı\'ndan kalan kerpiç teras, 2.000 yıllık tarihe bakar.'),
  'handan/idiom': ('Deyim Başkenti', '1.500\'den fazla Çince deyim bu topraklarda doğdu; Handan \'deyimler şehri\'dir.'),
  'handan/ciporcelain': ('Cizhou Porseleni', 'Beyaz üstüne siyah desenli Cizhou porseleni, halk seramiğinin klasiğidir.'),
  'daqing/oilpump': ('Petrol Sahası', 'Çin\'in en büyük petrol sahası, başını eğip kaldıran kuyu pompalarıyla doludur.'),
  'daqing/oilworker': ('Demir Adam', 'Petrol işçisi kahraman Wang Jinxi\'nin azmi, şehrin kuruluş ruhudur.'),
  'daqing/reedlake': ('Sulak Alan', 'Petrol kuyuları arasındaki geniş sazlık gölleri, turna ve kuğulara yuva olur.'),
  'daqing/hotspring': ('Kaplıca', 'Yer altından çıkan sıcak mineralli sular, soğuk kuzeyde şifalı bir mola sunar.'),
  'zibo/bbq': ('Zibo Mangalı', 'İnce şişlerin küçük mangalda pişirilip ince pidelere sarıldığı barbekü, ülkeyi sardı.'),
  'zibo/cuju': ('Cuju', 'Dünyanın en eski futbolu cuju, antik Qi başkenti Linzi\'de oynanırdı.'),
  'zibo/ceramic': ('Zibo Seramiği', 'Bin yıllık ocaklarıyla şehir, kuzey Çin\'in seramik merkezlerindendir.'),
  'zibo/glass': ('Liuli Camı', 'Renkli erimiş camdan elde yapılan liuli sanatı, ışıkla parlayan bir zanaattır.'),
  'taian/mounttai': ('Tai Dağı', 'Beş Kutsal Dağ\'ın başı Tai, imparatorların göğe kurban sunduğu en kutsal zirvedir.'),
  'taian/sunrise': ('Zirvede Gün Doğumu', 'Bulut denizi üstünde doğan güneşi izlemek, Tai Dağı\'na çıkmanın baş ödülüdür.'),
  'taian/stonesteps': ('Yedi Bin Basamak', 'Zirveye uzanan 7.000 taş basamak, hac yolunun fiziksel sınavıdır.'),
  'taian/daitemple': ('Dai Tapınağı', 'Dağ eteğindeki görkemli tapınak, imparatorların Tai törenlerine hazırlandığı yerdi.'),
  'lianyungang/monkey': ('Maymun Kral Dağı', '\'Batı\'ya Yolculuk\' destanının Maymun Kralı\'nın evi Huaguoshan burada yükselir.'),
  'lianyungang/seaport': ('Deniz Limanı', 'İpek Yolu\'nun doğu deniz kapısı, Avrasya demiryolunun Pasifik ucudur.'),
  'lianyungang/mountain': ('Yuntai Dağı', 'Sarp Yuntai zirveleri ve ormanlarıyla, Jiangsu\'nun en yüksek dağıdır.'),
  'lianyungang/crystal': ('Kristal Diyarı', 'Yakın Donghai, dünyanın en büyük kuvars kristal pazarlarından birine ev sahipliği yapar.'),
  'maanshan/libai': ('Şair Li Bai', 'Çin\'in en büyük şairi Li Bai\'nin son durağı ve mezarı bu nehir kasabasıdır.'),
  'maanshan/steel': ('Çelik Şehri', 'Magang çelik kombinası, şehri Çin\'in demir-çelik üslerinden biri yaptı.'),
  'maanshan/rivercliff': ('Caishiji Kayalığı', 'Yangtze\'ye dik inen kaya burnu, Li Bai efsanesinin geçtiği şiirsel manzaradır.'),
  'maanshan/moonwine': ('Ay ve Şarap', 'Li Bai\'nin dizelerindeki ay ve şarap, nehir kıyısı şenliklerinde hâlâ kutlanır.'),
  'longyan/tulou': ('Yongding Tulou', 'Dağlara serpilmiş dev yuvarlak Hakka kale-evleri UNESCO mirasıdır.'),
  'longyan/redmeeting': ('Gutian Toplantısı', 'Kızıl Ordu\'nun yön belirlediği tarihî toplantı bu köyde yapıldı.'),
  'longyan/hakka': ('Hakka Kültürü', 'Kuzeyden göçen Hakka halkı, kendine özgü dili ve mutfağını bu dağlarda yaşatır.'),
  'longyan/mountain': ('Guanzhi Dağı', 'Kızıl kayalıkları ve berrak göletleriyle dağ, güney Fujian\'ın doğa incisidir.'),
  'zunyi/huiyi': ('Zunyi Konferansı', '1935\'te devrimin kaderini değiştiren toplantının yapıldığı ev, kızıl tarihin dönüm noktasıdır.'),
  'zunyi/moutai': ('Moutai Kasabası', 'Chishui kıyısındaki kasabada damıtılan Moutai, Çin\'in ulusal içkisi sayılan efsanevi baijiu\'dur.'),
  'zunyi/loushan': ('Loushan Geçidi', 'Dağları yaran sarp geçit, Mao\'nun ünlü şiirine konu olan tarihi muharebenin sahnesidir.'),
  'zunyi/chishui': ('Chishui Şelaleleri', 'Kızıl Danxia kayalıklarından dökülen şelaleler ve bambu ormanları, \'kızıl nehir\' vadisini doldurur.'),
  'liupanshui/coolcity': ('Serin Şehir', 'Yazın 19 dereceyi geçmeyen havasıyla Liupanshui, \'Çin\'in serin başkenti\' diye anılır.'),
  'liupanshui/coal': ('Güneybatının Kömür Denizi', 'Zengin kömür damarlarıyla şehir, güneybatı Çin\'in enerji ocağıdır.'),
  'liupanshui/grassland': ('Wumeng Çayırları', 'Bulutlara komşu Wumeng platosunun uçsuz çayırları, at sürüleri ve rüzgâr gülleriyle bezelidir.'),
  'liupanshui/kiwi': ('Kırmızı Özlü Kivi', 'Serin yaylalarda yetişen kırmızı özlü kivi, şehrin tatlı yeşil hazinesidir.'),
  'anshun/huangguoshu': ('Huangguoshu Şelalesi', 'Asya\'nın en büyük şelalesi, gökkuşağı saçan sis bulutuyla 77 metreden gürler.'),
  'anshun/dixi': ('Dixi Yer Operası', 'Ahşap savaşçı maskeleriyle köy meydanlarında oynanan Dixi, \'Çin operasının yaşayan fosili\'dir.'),
  'anshun/batik': ('Batik Sanatı', 'Buyi ve Miao kadınlarının balmumuyla çizip çivit mavisine boyadığı kumaşlar, Anshun\'un imzasıdır.'),
  'anshun/tunpu': ('Tunpu Köyleri', 'Ming ordusunun taş garnizon köylerinde yaşayanlar, 600 yıllık kıyafet ve lehçeyi bugün de sürdürür.'),
  'bijie/azalea': ('Yüz Li Açelya Kuşağı', 'Her bahar dağ sırtlarını kaplayan açelya denizi, dünyanın en büyük doğal çiçek bahçesidir.'),
  'bijie/zhijin': ('Zhijin Mağarası', 'Dev sarkıt ormanlarıyla \'yeraltı sarayı\' Zhijin, Çin\'in en görkemli mağarasıdır.'),
  'bijie/caohai': ('Caohai Gölü Turnaları', 'Weining\'deki sığ göl, her kış nadir kara boyunlu turnaların kışlağı olur.'),
  'bijie/potato': ('Patates Başkenti', 'Serin yaylaların patatesi Bijie\'yi Çin\'in patates ambarı yapar; Weining patatesi ülkece ünlüdür.'),
  'qujing/rapeseed': ('Luoping Kolza Denizi', 'Her şubat Luoping ovasını kaplayan altın sarısı kolza tarlaları, arıcıları ve fotoğrafçıları çeker.'),
  'qujing/ham': ('Xuanwei Jambonu', 'Asırlardır tuzlanıp kurutulan Xuanwei jambonu, Yunnan sofrasının gurur kaynağıdır.'),
  'qujing/jiulong': ('Jiulong Şelaleleri', '\'Dokuz Ejder\' nehrinin basamak basamak dökülen on şelalesi, Çin\'in en güzel şelale dizisidir.'),
  'qujing/sandforest': ('Renkli Kum Ormanı', 'Rüzgârın yonttuğu rengârenk kum sütunları, Luliang\'da doğal bir heykel bahçesi kurar.'),
  'yuxi/fuxian': ('Fuxian Gölü', 'Çin\'in en derin ikinci gölü, kristal berraklığındaki suyuyla bir dağ aynasıdır.'),
  'yuxi/nieer': ('Besteci Nie Er', 'Ulusal marşın bestecisi Nie Er\'in memleketi, onu müzik parkı ve anıtıyla onurlandırır.'),
  'yuxi/chengjiang': ('Chengjiang Fosilleri', '530 milyon yıllık Kambriyen fosil yatakları, hayvan yaşamının şafağını gösteren UNESCO mirasıdır.'),
  'yuxi/kiln': ('Yuxi Fırını', 'Yuan döneminden kalma antik fırın, Yunnan\'ın mavi-beyaz seramiğinin doğduğu yerdir.'),
  'dali/threepagodas': ('Üç Pagoda', 'Bin yıldır Cangshan eteklerinde yükselen üç zarif pagoda, antik Dali krallığının simgesidir.'),
  'dali/erhai': ('Erhai Gölü', 'Kulak biçimli dağ gölü Erhai, balıkçı sandalları ve göl kıyısı köyleriyle bir tablo gibidir.'),
  'dali/cangshan': ('Cangshan Dağları', 'On dokuz zirvesi karla kaplı Cangshan, Dali\'nin ardında yeşil bir perde gibi yükselir.'),
  'dali/wind': ('Rüzgâr, Çiçek, Kar, Ay', 'Xiaguan rüzgârı, Shangguan çiçeği, Cangshan karı ve Erhai ayı — Dali\'nin dört güzelliği bir şiirdir.'),
  'lijiang/oldtown': ('Lijiang Eski Şehri', 'Kanallar ve kiremit çatılı ahşap evlerle örülü UNESCO şehri, Naxi kültürünün yaşayan kalbidir.'),
  'lijiang/snowmountain': ('Yeşim Ejder Karlı Dağı', '5.596 metrelik buzullu zirve, şehrin üzerinde uyuyan bir yeşim ejder gibi parlar.'),
  'lijiang/dongba': ('Dongba Yazısı', 'Naxi rahiplerinin resim-yazısı Dongba, dünyada hâlâ yaşayan tek piktografik yazıdır.'),
  'lijiang/tigerleaping': ('Kaplan Atlayan Geçidi', 'Efsaneye göre bir kaplanın tek sıçrayışta aştığı geçit, dünyanın en derin kanyonlarındandır.'),
  'lincang/dianhong': ('Dianhong Çayı', 'Fengqing\'in altın tomurcuklu kızıl çayı Dianhong, dünyaya Yunnan\'ın adını duyurdu.'),
  'lincang/wadrum': ('Va Ahşap Davulu', 'Va halkının kutsal ahşap davulları, dağ köylerinde saç savuran davul dansıyla gümbürder.'),
  'lincang/teatrees': ('Antik Çay Ağaçları', 'Binlerce yıllık yabani çay ağaçlarının anavatanı Lincang, çayın doğduğu ormanları saklar.'),
  'lincang/lancang': ('Lancang Nehri', 'Mekong\'un yukarı kolu Lancang, dev barajlarıyla vadileri aydınlatarak güneye akar.'),
  'puer/tea': ('Pu\'er Çayı', 'Yıllandıkça olgunlaşan preslenmiş Pu\'er çayı, adını bu dağ şehrinden alan yaşayan bir hazinedir.'),
  'puer/coffee': ('Çin\'in Kahve Başkenti', 'Çin kahvesinin yarıdan fazlası Pu\'er\'in sisli yamaçlarında yetişir; şehir latte kokar.'),
  'puer/teahorse': ('Çay-At Yolu', 'Katır kervanlarının çayı Tibet\'e taşıdığı antik yol, Pu\'er\'den başlayıp bulutlara tırmanırdı.'),
  'puer/peafowl': ('Yeşil Tavus Kuşu', 'Nadir yeşil tavus kuşunun son sığınaklarından olan tropik ormanlar, şehrin yaban tacıdır.'),
  'baoshan/volcano': ('Tengchong Volkanları', 'Doksan yedi sönmüş volkan konisi, Tengchong ovasını ay yüzeyine çevirir.'),
  'baoshan/rehai': ('Rehai Kaplıcaları', 'Kaynayan \'Sıcak Deniz\' vadisinde gayzerler tüter; yumurtalar kaynak sularında pişer.'),
  'baoshan/heshun': ('Heshun Kasabası', 'Yurtdışına açılan tüccarların taş kasabası Heshun, Çin\'in en eski köy kütüphanesini barındırır.'),
  'baoshan/gaoligong': ('Gaoligong Dağları', 'Kelebek vadileri ve sıcak ormanlarıyla Gaoligong, bir canlı türleri hazinesidir.'),
  'deyang/sanxingdui': ('Sanxingdui Kalıntıları', 'Fırlak gözlü dev bronz maskeler, 3.000 yıllık gizemli Shu uygarlığını gün ışığına çıkardı.'),
  'deyang/jiannanchun': ('Jiannanchun Likörü', 'Tang sarayına sunulan Mianzhu baijiu\'su Jiannanchun, bin beş yüz yıldır damıtılır.'),
  'deyang/nianhua': ('Mianzhu Yılbaşı Baskıları', 'El boyaması tahta baskı yılbaşı resimleri, kapılara bereket ve renk asar.'),
  'deyang/turbine': ('Ağır Sanayi Başkenti', 'Ülkenin dev türbin ve jeneratörlerinin çoğu Deyang\'ın atölyelerinde dövülür.'),
  'mianyang/libai': ('Li Bai\'nin Memleketi', 'Şairlerin ölümsüzü Li Bai, Jiangyou\'nun dağları arasında büyüdü; dizeleri hâlâ burada yankılanır.'),
  'mianyang/sciencecity': ('Bilim Şehri', 'Çin\'in tek \'Bilim ve Teknoloji Şehri\' unvanlı kenti, laboratuvarları ve ekranlarıyla geleceği kurar.'),
  'mianyang/qiang': ('Qiang Taş Kuleleri', 'Beichuan\'ın dağ köylerinde Qiang halkının taş gözetleme kuleleri asırlardır ayaktadır.'),
  'mianyang/mifen': ('Mianyang Pirinç Şehriyesi', 'İnce pirinç şehriyesi, sabahları tavuk ve sakatat suyuyla buharlanan şehrin uyanışıdır.'),
  'nanchong/langzhong': ('Langzhong Antik Şehri', 'Feng shui\'ye göre kurulmuş en iyi korunan antik şehir, nehir kıvrımının kucağında uyur.'),
  'nanchong/silk': ('İpek Başkenti', 'İki bin yıllık dokuma geleneğiyle Nanchong, Çin\'in batıdaki ipek başkentidir.'),
  'nanchong/zhangfei': ('Zhang Fei Sığır Eti', 'Üç Krallık kahramanı Zhang Fei\'nin şehrinde kurutulan baharatlı sığır eti, onun adını taşır.'),
  'nanchong/zhude': ('Zhu De\'nin Memleketi', 'Mareşal Zhu De\'nin Yilong\'daki mütevazı evi, modern tarihin hac duraklarındandır.'),
  'yibin/wuliangye': ('Wuliangye Likörü', 'Beş tahıldan damıtılan Wuliangye, Çin\'in en değerli baijiu markalarındandır.'),
  'yibin/firstcity': ('Yangtze\'nin İlk Şehri', 'Min ve Jinsha nehirlerinin kavuştuğu yerde Yangtze doğar; Yibin bu yüzden \'ilk şehir\'dir.'),
  'yibin/bamboosea': ('Shunan Bambu Denizi', 'Yüz yirmi tepeyi örten bambu okyanusu, rüzgârda dalgalanan yeşil bir denizdir.'),
  'yibin/ranmian': ('Alevli Erişte', 'Yağıyla tutuşturulabilecek kadar susuz yoğrulan \'ranmian\', Yibin kahvaltısının acılı yıldızıdır.'),
  'luzhou/laojiao': ('Laojiao Mahzenleri', '1573\'ten beri kesintisiz kullanılan çamur fermantasyon çukurları, kokulu baijiu\'nun kalbidir.'),
  'luzhou/port': ('Yangtze Limanı', 'İki nehrin kavşağındaki liman şehri, Sichuan\'ın denize açılan su kapısıdır.'),
  'luzhou/longan': ('Longan Bahçeleri', 'Nehir vadilerinin sıcak yamaçlarında yetişen longan, \'ejder gözü\' denen bal tatlı meyvedir.'),
  'luzhou/umbrella': ('Yağlı Kağıt Şemsiyeler', 'Fenshui ustalarının el yapımı yağlı kağıt şemsiyeleri, dört yüz yıllık zarif bir zanaattır.'),
  'leshan/giantbuddha': ('Leshan Dev Budası', 'Kayaya oyulmuş 71 metrelik oturan Buda, bin iki yüz yıldır nehirlerin kavşağını izler.'),
  'leshan/emei': ('Emei Dağı', 'Budizmin dört kutsal dağından Emei\'nin Altın Zirvesi, bulut denizinin üstünde parlar.'),
  'leshan/monkeys': ('Emei Makakları', 'Dağ patikalarının haylaz makakları, hacıların çantalarını arsızca yoklamalarıyla ünlüdür.'),
  'leshan/qiaojiao': ('Qiaojiao Sığır Çorbası', 'Şifalı otlarla kaynayan sığır çorbası \'qiaojiao\', Leshan sokak sofralarının yüz yıllık klasiğidir.'),
  'zigong/saltwell': ('Bin Metrelik Tuz Kuyuları', 'Dünyada bin metreyi ilk aşan Shenhai kuyusu, iki bin yıllık tuz şehrinin zaferidir.'),
  'zigong/lantern': ('Zigong Fener Festivali', 'Devasa ışıklı fener bahçeleri, her yeni yılda şehri bir masal diyarına çevirir.'),
  'zigong/dinosaur': ('Dinozor Müzesi', 'Jura katmanlarından fışkıran binlerce fosil, Zigong\'u Çin\'in dinozor başkenti yapar.'),
  'zigong/rabbit': ('Soğuk Tavşan', 'Acılı soğuk servis edilen \'lengtu\' tavşanı, Sichuan\'ın en cesur mezesinin memleketi buradadır.'),
  'panzhihua/steel': ('Vanadyum-Titanyum Başkenti', 'Dağların içine kurulmuş dev çelik kenti, dünyanın en zengin vanadyum-titanyum yataklarını işler.'),
  'panzhihua/fruitvalley': ('Güneş Meyveleri Vadisi', 'Kurak-sıcak vadinin mangoları ve narları, kışın bile güneşle olgunlaşır.'),
  'panzhihua/sunshine': ('Kış Güneşi Şehri', 'Yılda 2.700 saat güneşiyle Panzhihua, kışı ılık geçirmek isteyenlerin sağlık durağıdır.'),
  'panzhihua/jinsha': ('Jinsha Nehri', 'Altın kumlu Jinsha, derin vadileri yararak şehrin ortasından coşkuyla akar.'),
  'dazhou/gas': ('Doğalgaz Başkenti', 'Puguang dev gaz sahası, Dazhou\'yu Çin\'in doğalgaz enerji üssü yapar.'),
  'dazhou/ba': ('Ba Krallığı Mirası', 'Söğüt yaprağı kılıçlarıyla antik Ba savaşçılarının toprakları, Luojiaba kalıntılarında konuşur.'),
  'dazhou/dengying': ('Lamba Gölgesi Sığır Eti', 'Işığı geçirecek kadar ince kesilen baharatlı \'dengying\' eti, adını gölge oyunundan alır.'),
  'dazhou/hanque': ('Han Taş Kapıları', 'Quxian\'daki iki bin yıllık taş \'que\' kuleleri, Han mimarisinin ayakta kalan zarafetidir.'),
  'guangyuan/jianmen': ('Jianmen Geçidi', '\'Bir kişi tutsa on bin kişi geçemez\' denen kılıç dağı geçidi, Shu yolunun kilididir.'),
  'guangyuan/wuzetian': ('Wu Zetian\'ın Doğduğu Şehir', 'Çin\'in tek kadın imparatoru Wu Zetian burada doğdu; Huangze Tapınağı onu bin yıldır anar.'),
  'guangyuan/plankroad': ('Antik Tahta Yollar', 'Uçurumlara çakılmış tahta yollar, \'göğe çıkmaktan zor\' Shu yolunun cesaret anıtıdır.'),
  'guangyuan/cypress': ('Cuiyun Servi Koridoru', 'Üç Krallık\'tan kalma on binlerce antik servi, antik yolu yeşil bir tünele çevirir.'),
  'yaan/panda': ('Pandanın Anavatanı', 'Dev panda bilime ilk kez 1869\'da Baoxing\'de tanıtıldı; Bifengxia üssü bu mirası yaşatır.'),
  'yaan/rain': ('Yağmur Şehri', '\'Ya yağmuru\' neredeyse her gece çatıları yıkar; şehir yeşilin bin tonuyla parlar.'),
  'yaan/mengding': ('Mengding Dağı Çayı', 'İnsan eliyle çay ilk kez iki bin yıl önce Mengding\'de dikildi; dağ, çay kültürünün beşiğidir.'),
  'yaan/yayu': ('Ya Balığı', 'Kar sularında yetişen efsanevi Ya balığı, kaynayan güveçlerde şehrin sofra gururudur.'),
  'xianyang/qincapital': ('Qin İmparatorluk Başkenti', 'Çin\'i ilk birleştiren Qin hanedanının başkenti burasıydı; imparatorluğun yolu Xianyang\'dan geçti.'),
  'xianyang/qianling': ('Qianling Anıtmezarı', 'Wu Zetian ile eşinin dağa oyulan ortak mezarı, yazısız dikilitaşıyla tarihe meydan okur.'),
  'xianyang/zhengguo': ('Zhengguo Kanalı', 'İki bin yıllık sulama kanalı, Guanzhong ovasını Qin\'in tahıl ambarına çevirdi.'),
  'xianyang/guokui': ('Guokui Gözlemesi', 'Kazan kapağı kadar büyük ve çıtır \'guokui\' ekmeği, Shaanxi sofrasının asırlık atıştırmalığıdır.'),
  'baoji/bronze': ('Bronz Eserler Başkenti', '\'Çin\' adının bilinen ilk yazımını taşıyan He zun dahil binlerce Zhou bronzu, Baoji\'de gün yüzüne çıktı.'),
  'baoji/famen': ('Famen Tapınağı', 'Buda\'nın parmak kemiği kalıntısını saklayan Famen, Tang imparatorlarının kutsal hazinesiydi.'),
  'baoji/taibai': ('Taibai Dağı', 'Qinling\'in 3.771 metrelik çatısı Taibai, yazın bile karlı zirvesiyle efsanelere konu olur.'),
  'baoji/saozi': ('Saozi Eriştesi', 'Ekşi-acı et soslu Qishan \'saozi\' eriştesi, üç bin yıllık Zhou mutfağının yaşayan tadıdır.'),
  'sanming/danxia': ('Taining Danxia', 'Kızıl kayalıkları ve kanyonlarıyla UNESCO jeoparkı, gökten inmiş bir taş labirentidir.'),
  'sanming/shaxian': ('Sha İlçesi Atıştırmalıkları', 'Ucuz wonton ve karışık eriştesiyle Sha İlçesi mutfağı tüm Çin\'e yayıldı.'),
  'sanming/forest': ('Yeşil Başkent', 'Çin\'in en ormanlık şehri Sanming, temiz havası ve yeşil dağlarıyla nefes aldırır.'),
  'sanming/goldenlake': ('Altın Göl', 'Danxia kayalıkları arasında uzanan göl, tekne turlarıyla keşfedilir.'),
  'ningde/mudflat': ('Xiapu Gelgit Düzlükleri', 'Gelgitle değişen ışıltılı çamur düzlükleri, dünyanın en çok fotoğraflanan kıyılarındandır.'),
  'ningde/whitetea': ('Fuding Beyaz Çayı', 'Tüylü tomurcuklarıyla kurutulan beyaz çay, yıllandıkça değer kazanır.'),
  'ningde/taimu': ('Taimu Dağı', 'Denize bakan granit kuleleri ve mağaralarıyla dağ, \'denizin yanındaki peri diyarı\'dır.'),
  'ningde/croaker': ('Sarı Kroker Balığı', 'Sakin koylarda yetiştirilen büyük sarı kroker balığı, şehrin deniz hazinesidir.'),
  'shaoguan/redcliff': ('Danxia Dağı', '\'Danxia\' yer şeklinin adını aldığı kızıl kayalık dağ, eşsiz oyma kuleleriyle ünlüdür.'),
  'shaoguan/chantemple': ('Nanhua Tapınağı', 'Zen Budizminin Altıncı Patriği Huineng\'in tapınağı, mezhebin kutsal merkezidir.'),
  'shaoguan/ancestor': ('Zhuji Sokağı', 'Milyonlarca güneyli Çinlinin atalarının göç ettiği sokak, bir kök-bulma yeridir.'),
  'shaoguan/yaodance': ('Yao Halkı', 'Dağ köylerinde yaşayan Yao halkı, rengârenk kostümleri ve davullu danslarıyla bilinir.'),
  'zhanjiang/oyster': ('Zhanjiang İstiridyesi', 'Sıcak güney sularında yetişen iri istiridyeler, kömürde ızgara edilip sofraları süsler.'),
  'zhanjiang/navy': ('Donanma Limanı', 'Güney Deniz Filosu\'na ev sahipliği yapan derin liman, ülkenin güney deniz kapısıdır.'),
  'zhanjiang/mangrove': ('Mangrov Ormanı', 'Çin\'in en büyük mangrov ormanı, gelgit sularında balıkçıllara ve yengeçlere yuva olur.'),
  'zhanjiang/donghai': ('Donghai Adası', 'Uzun kumsalı ve rüzgârıyla ada, güneşlenme ve sörfün gözde durağıdır.'),
  'maoming/lychee': ('Liçi Başkenti', 'Çin\'in en büyük liçi üreticisi Maoming, imparatorlara liçi yollayan topraklardır.'),
  'maoming/refinery': ('Petrokimya Üssü', 'Güney Çin\'in en büyük rafinerilerinden biri, şehrin sanayi gücünü besler.'),
  'maoming/ladyxian': ('Lady Xian', 'Güneyi birleştiren kadın kahraman Lady Xian, halkın bin yıldır andığı bir efsanedir.'),
  'maoming/seaside': ('Sahil', '\'Çin\'in Bir Numaralı Plajı\' sayılan uzun sahil, ailelere altın kumlar sunar.'),
  'zhaoqing/sevenstar': ('Yedi Yıldız Kayalıkları', 'Göl üstünde yükselen yedi kireçtaşı tepe, \'Guangdong\'un Guilin\'i\' diye anılır.'),
  'zhaoqing/inkstone': ('Duan Mürekkep Taşı', 'Kaligrafinin dört hazinesinden Duan mürekkep taşı, bin yıldır burada yontulur.'),
  'zhaoqing/dinghu': ('Dinghu Dağı', 'Çin\'in ilk doğa koruma alanı, gür yağmur ormanı ve şelaleleriyle \'canlı oksijen barı\'dır.'),
  'zhaoqing/songwall': ('Song Şehir Suru', 'Tam korunmuş Song dönemi suru, antik Zhaoqing\'i bir tarih halkasıyla sarar.'),
  'huizhou/westlake': ('Huizhou Batı Gölü', 'Şair Su Shi\'nin sürgünde sevdiği göl, söğütleri ve setleriyle bir şiirdir.'),
  'huizhou/luofu': ('Luofu Dağı', 'Taocu münzevilerin ve şifalı bitkilerin dağı, \'güneyin ilk kutsal dorukları\'ndandır.'),
  'huizhou/alchemy': ('Ge Hong Simyası', 'Simyacı-hekim Ge Hong, geleneksel tıbbın temellerini bu dağda yazdı.'),
  'huizhou/xunliao': ('Xunliao Körfezi', 'Berrak suları ve yumuşak kumuyla körfez, güney sahilinin sakin tatil noktasıdır.'),
  'meizhou/weilongwu': ('Hakka Başkenti', '\'Dünya Hakka başkenti\' Meizhou, at nalı biçimli geleneksel weilongwu evleriyle bilinir.'),
  'meizhou/saltchicken': ('Tuzda Tavuk', 'Sıcak tuza gömülerek pişirilen Hakka tavuğu, narin etiyle imza lezzettir.'),
  'meizhou/football': ('Futbolun Memleketi', 'Çin futbolunun beşiği sayılan şehir, ülkeye nesiller boyu yıldız oyuncu yetiştirdi.'),
  'meizhou/plum': ('Erik Çiçeği', 'Adı \'erik\' anlamına gelen şehir, kışın açan erik çiçekleriyle bezenir.'),
  'jiangmen/diaolou': ('Kaiping Kuleleri', 'Yurtdışından dönen göçmenlerin yaptığı çok katlı kale-kuleler UNESCO mirasıdır.'),
  'jiangmen/qiaoxiang': ('Gurbetçi Diyarı', 'Dünyaya yayılmış milyonlarca gurbetçinin memleketi, Doğu-Batı kültürünü harmanlar.'),
  'jiangmen/chenpi': ('Xinhui Mandalina Kabuğu', 'Yıllandırılan Xinhui mandalina kabuğu, hem baharat hem değerli bir ilaçtır.'),
  'jiangmen/birds': ('Kuşlar Cenneti', 'Tek bir dev banyan ağacının oluşturduğu koru, on binlerce balıkçıla yuva olur.'),
  'yangjiang/knife': ('Bıçak Başkenti', 'Çin\'in mutfak bıçaklarının büyük kısmı, asırlık demircilik geleneğiyle burada dövülür.'),
  'yangjiang/shipwreck': ('Nanhai 1 Batığı', 'Deniz İpek Yolu\'ndan kalan Song gemisi, hazinesiyle bir su altı müzesinde sergilenir.'),
  'yangjiang/hailing': ('Hailing Adası', 'Güneşli plajları ve dalgalarıyla ada, Guangdong\'un gözde deniz tatil yeridir.'),
  'yangjiang/kite': ('Uçurtma Şehri', 'Weifang\'la birlikte Çin\'in iki uçurtma başkentinden biri, gökyüzünü her sonbahar süsler.'),
  'qingyuan/rafting': ('Rafting Diyarı', 'Coşkun dağ dereleriyle Qingyuan, Çin\'in \'rafting memleketi\' diye anılır.'),
  'qingyuan/chicken': ('Qingyuan Tavuğu', 'İnce kemikli, lezzetli yerel tavuk ırkı, Kanton sofrasının en aranan kümes hayvanıdır.'),
  'qingyuan/hotspring': ('Kaplıcalar', 'Dağ vadilerinden çıkan sıcak mineralli sular, hafta sonu kaçamaklarının merkezidir.'),
  'qingyuan/yaoterrace': ('Yao Pirinç Terasları', 'Liannan Yao halkının dağ yamaçlarına oyduğu teraslar, asırlık emeğin merdivenidir.'),
  'chaozhou/guangjibridge': ('Guangji Köprüsü', 'Ortasındaki sandallarla açılıp kapanan antik köprü, Çin\'in dört ünlü köprüsünden biridir.'),
  'chaozhou/woodcarving': ('Yaldızlı Ahşap Oyma', 'Altın varakla kaplı çok katmanlı ahşap oymalar, tapınakları ışıltıyla doldurur.'),
  'chaozhou/chaoxiu': ('Chaozhou İşlemesi', 'Kabartmalı altın iplik nakışıyla Chaozhou işlemesi, güney Çin\'in en gösterişlisidir.'),
  'chaozhou/kaiyuan': ('Kaiyuan Tapınağı', '1.200 yıllık tapınak, Tang döneminden kalma sakin avlularıyla şehrin kalbidir.'),
  'jieyang/citygate': ('Jinxian Kapısı', 'Nehre bakan zarif ahşap kule kapısı, antik Jieyang\'ın ayakta kalan simgesidir.'),
  'jieyang/jade': ('Yeşim Başkenti', 'Yangmei kasabası, Çin\'in en büyük yeşim oyma ve ticaret merkezlerindendir.'),
  'jieyang/jieyanglou': ('Jieyang Kulesi', 'Geleneksel saçaklı dev kule, Chaoshan kültürünün modern bir anıtıdır.'),
  'jieyang/beefbroth': ('Chaoshan Dana Çorbası', 'Taze dananın berrak suda anında haşlandığı çorba, bölgenin gurur lezzetidir.'),
  'yunfu/marble': ('Taş Krallığı', 'Mermer ve taş işlemenin başkenti Yunfu, dünyaya cilalı taş ihraç eder.'),
  'yunfu/patriarch': ('Altıncı Patrik', 'Zen ustası Huineng\'in doğduğu topraklar, Guoen Tapınağı ile kutsanır.'),
  'yunfu/tianlu': ('Tianlu Dağı', 'Bulutlara değen zirveleri ve çay bahçeleriyle dağ, şehrin yeşil tacıdır.'),
  'yunfu/xijiang': ('Batı Nehri', 'Güneyin büyük su yolu olan İnci Nehri\'nin ana kolu, şehrin önünden akar.'),
  'liuzhou/luosifen': ('Salyangoz Eriştesi', 'Keskin kokulu ekşi-acı salyangoz eriştesi \'luosifen\', tüm Çin\'i saran bir lezzettir.'),
  'liuzhou/autocity': ('Otomobil Şehri', 'Halkın aldığı küçük şehir araçlarıyla Liuzhou, Çin\'in en büyük otomobil üslerindendir.'),
  'liuzhou/karst': ('Liu Nehri Karstı', 'Şehri saran kireçtaşı tepeler ve nehir kıvrımı, sanayi kentine doğa güzelliği katar.'),
  'liuzhou/liuhou': ('Şair Liu Zongyuan', 'Tang şairi ve valisi Liu Zongyuan\'ın anısı, şehir parkında bir tapınakla yaşar.'),
  'wuzhou/gemstone': ('Yapay Mücevher Başkenti', 'Dünya yapay değerli taşlarının büyük kısmı, bu nehir kentinin atölyelerinde kesilir.'),
  'wuzhou/liubaotea': ('Liubao Çayı', 'Yıllandırılan koyu Liubao çayı, nemli güneyin sindirim dostu klasik içeceğidir.'),
  'wuzhou/turtlejelly': ('Kaplumbağa Jölesi', 'Şifalı otlardan yapılan acımsı siyah jöle \'guilinggao\', sıcak günlerin ferahlatıcısıdır.'),
  'wuzhou/dragonmother': ('Ejderha Ana Tapınağı', 'Nehir tanrıçası Ejderha Ana\'ya adanan tapınak, nehir halkının asırlık inancıdır.'),
  'beihai/silverbeach': ('Gümüş Kumsal', 'Pırıl pırıl ince kumuyla \'göğün altındaki birinci plaj\', kilometrelerce uzanır.'),
  'beihai/pearl': ('İnci Şehri', 'Hepu\'nun Güney Denizi incileri, imparatorluk haraçlarından beri en kıymetlisi sayılır.'),
  'beihai/weizhou': ('Weizhou Adası', 'Çin\'in en genç volkanik adası, kara kayalıkları ve mercanlarıyla dalgıçları çeker.'),
  'beihai/oldstreet': ('Eski Sokak', 'Yüz yıllık sömürge revaklı binalar, Deniz İpek Yolu limanının geçmişini yaşatır.'),
  'qinzhou/nixingpottery': ('Nixing Çömleği', 'Fırında kendiliğinden renk değiştiren Nixing çömlekçiliği, Çin\'in dört ünlü çömleğindendir.'),
  'qinzhou/dolphin': ('Beyaz Yunus', 'Sanniang Körfezi\'nde yüzen nadir Çin beyaz yunusları, şehrin sevimli simgesidir.'),
  'qinzhou/oysterfarm': ('İstiridye Diyarı', 'Sığ koylarda yetiştirilen dev istiridyeler, Qinzhou\'yu Çin\'in istiridye başkenti yapar.'),
  'qinzhou/general': ('General Feng Zicai', 'Sınırı savunan yaşlı general Feng Zicai\'nin memleketi, kahramanlık anılarıyla doludur.'),
  'guigang/lotus': ('Nilüfer Şehri', 'Yaz boyu açan dev nilüfer tarlalarıyla Guigang, \'nilüfer şehri\' diye anılır.'),
  'guigang/uprising': ('Jintian Ayaklanması', 'Tarihi sarsan Taiping Ayaklanması\'nın ilk kıvılcımı bu topraklarda çakıldı.'),
  'guigang/nanshan': ('Nanshan Tapınağı', 'Kayaya oyulmuş bin yıllık mağara tapınağı, imparator yazıtlarıyla bezelidir.'),
  'guigang/sugarcane': ('Şeker Kamışı', 'Verimli nehir ovası, Çin\'in en büyük şeker üretiminin tatlı kaynağıdır.'),
  'yulin/medicine': ('Şifalı Ot Pazarı', 'Güney Çin\'in en büyük geleneksel ilaç pazarı, binlerce şifalı bitkiyi bir araya getirir.'),
  'yulin/goldenpalace': ('Yuntian Sarayı', 'Altın kaplı dev kültür sarayı, görkemli heykelleri ve salonlarıyla şaşırtır.'),
  'yulin/lychee': ('Liçi Bahçeleri', 'Sıcak tepelerde yetişen tatlı liçi, yaz pazarlarının kırmızı hazinesidir.'),
  'yulin/beef': ('Yulin Sığır Eti', 'Baharatla kurutulan \'niuba\' sığır eti, bölgenin asırlık imza atıştırmalığıdır.'),
  'baise/redbase': ('Baise Ayaklanması', 'Genç Deng Xiaoping\'in yönettiği ayaklanma, kızıl tarihin önemli bir dönüm noktasıdır.'),
  'baise/sinkhole': ('Leye Obrukları', 'Dünyanın en büyük dev obruk kümesi, derinliklerinde gizli ormanlar barındırır.'),
  'baise/mango': ('Mango Başkenti', 'Sıcak vadileriyle Baise, Çin\'in en büyük mango bahçelerine ev sahipliği yapar.'),
  'baise/aluminum': ('Alüminyum Şehri', 'Zengin boksit yataklarıyla şehir, Çin\'in alüminyum sanayisinin güney üssüdür.'),
  'hechi/longevity': ('Bama Uzun Ömür Diyarı', 'Yüz yaşını aşan sakinleriyle Bama, dünyanın ünlü \'uzun ömür memleketi\'dir.'),
  'hechi/folksong': ('Liu Sanjie', 'Türkü perisi Liu Sanjie\'nin efsanesi, karşılıklı şarkı atışmalarında yaşar.'),
  'hechi/bronzedrum': ('Tunç Davul', 'Zhuang ve dağ halklarının kutsal tunç davulları, en yoğun şekilde burada toplanır.'),
  'hechi/geopark': ('Karst Jeoparkı', 'Obrukları, mağaraları ve yer altı nehirleriyle bölge, bir karst harikalar diyarıdır.'),
  'laibin/sugarcity': ('Şeker Başkenti', 'Uçsuz şeker kamışı tarlalarıyla Laibin, \'Çin\'in şeker şehri\' diye anılır.'),
  'laibin/yao': ('Dayao Dağı Yao', 'Jinxiu\'nun Dayao dağlarında yaşayan Yao halkı, beş ayrı boyuyla kültür hazinesidir.'),
  'laibin/hongshui': ('Kızıl Su Nehri', 'Vadileri yaran güçlü Kızıl Su Nehri, barajları ve manzaralarıyla bölgeyi besler.'),
  'laibin/shengtang': ('Shengtang Dağı', 'Bulut denizi ve şelaleleriyle dağ, Dayao sıradağlarının en yüksek zirvesidir.'),
  'chongzuo/waterfall': ('Detian Şelalesi', 'Vietnam sınırındaki Detian, Asya\'nın en büyük ülkeler arası şelalesidir.'),
  'chongzuo/langur': ('Beyaz Başlı Langur', 'Yalnızca bu kireçtaşı tepelerde yaşayan nadir beyaz başlı langur, dünyanın en ender maymunlarındandır.'),
  'chongzuo/rockart': ('Huashan Kaya Resimleri', 'Zuojiang kayalıklarına 2.000 yıl önce çizilen kızıl figürler UNESCO mirasıdır.'),
  'chongzuo/borderpass': ('Dostluk Geçidi', 'Vietnam\'a açılan tarihî sınır kapısı, güney İpek Yolu\'nun kara kapısıdır.'),
  'beijing/great-wall': ('Çin Seddi', 'Kuzey sınırlarını korumak için yüzyıllar boyunca inşa edilen, 20.000 km\'yi aşan dünyanın en uzun savunma yapısı. Pekin\'e en yakın Badaling kesimi; taş basamakları, surları ve sırtlar boyunca uzanan gözetleme kuleleriyle en çok ziyaret edilen bölümdür.'),
  'beijing/temple': ('Cennet Tapınağı', 'Ming ve Qing imparatorlarının her yıl bol hasat için gökyüzüne dua ettiği kutsal tapınak kompleksi. Tek bir çivi kullanılmadan inşa edilen üç katmanlı yuvarlak mavi çatısı, Çin mimarisinin en tanınan simgelerinden biridir.'),
  'beijing/pagoda': ('Tianning Pagodası', 'Liao Hanedanı\'ndan kalma, yaklaşık 57 metre yüksekliğinde 13 katlı tuğla pagoda. Oymalı kabartmaları ve sekizgen gövdesiyle Pekin\'in ayakta kalan en eski yapılarından biridir ve şehrin bin yıllık geçmişine tanıklık eder.'),
  'beijing/opera': ('Pekin Operası', 'Şarkı, konuşma, dövüş sanatları ve akrobasinin birleştiği 200 yıllık geleneksel Çin sahne sanatı. Oyuncuların renkli yüz makyajı (lianpu) her karakterin kişiliğini anlatır: kırmızı sadakati, beyaz kurnazlığı simgeler.'),
};
